function response = SimonResponse(interval)% response = SimonResponse(interval);% % Get the subject response for the simultaneous masking% experiment.% % Returns 1 for correct.%         0 for incorrect.%        -1 for repeat of trial.%				 -2 for abort experiment.%% 8/25/97	ccc		Wrote it.while (1)% 	but = abs(getChar);    [keyIsDown, secs, key, deltaSecs] = KbCheck();    but=find(key==1);		% Observer guesses interval 1	if (but == 92)		if (interval == 1)			response = 1;		else			response = 0;		end		return	% Observer guesses interval 2	elseif (but == 94)		if (interval == 2)			response = 1;		else			response = 0;		end		return;	% Observer requests trial repeat	elseif (but == 44)		response = -1;		return	% Observer requests experiment abort	elseif (but == 41)		response = -2;		return;	endend		